using SkiaSharpChartEngine; using SkiaSharpChartEngine.Models; class Program { static void Main(string[] args) { var engine = ChartEngine.Create(); var chart = new Chart(ChartType.LineChart) { Configuration = new ChartConfiguration { Title = "Basic Line Chart", Width = 800, Height = 600 } }; var series = new ChartSeries("Data", "#FF6B6B"); series.AddDataPoint(1, 10); series.AddDataPoint(2, 20); series.AddDataPoint(3, 15); chart.AddSeries(series); var result = engine.RenderChart(chart); } }